    }

    assert results == ClassifyAll(sentences[..i]) + [ClassifySentence(sentences[i])];
    assert sentences[..i+1] == sentences[..i] + [sentences[i]];
    assert sentences[..i+1][..|sentences[..i+1]|-1] == sentences[..i];
    ClassifyAllAppend(sentences[..i+1]);
  }

}
